import ThemeToggle from "./ThemeToggle";
import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import axios from "axios";
import ReCAPTCHA from "react-google-recaptcha";


const LoginAdmin = () => {
  const navigate = useNavigate();
  const [identifier, setIdentifier] = useState(""); // Email or Phone
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("admin"); // 'admin', 'centre', 'user'
  const [error, setError] = useState("");
const [recaptchaToken, setRecaptchaToken] = useState("");


 const RECAPTCHA_SITE_KEY = process.env.REACT_APP_RECAPTCHA_SITE_KEY;

 const handleRecaptchaChange = (token) => {
    setRecaptchaToken(token);
  };

  const handleLogin = async (e) => {
    e.preventDefault();

    if (!role || !identifier || !password) {
      setError("All fields are required.");
      return;
    }

       if (!recaptchaToken) {
      setError("Please complete the reCAPTCHA verification.");
      return;
    }


    let apiUrl = "";
    if (role === "admin") {
      apiUrl = `${process.env.REACT_APP_BACKEND_URL}/api/admin/adminLogin`;
    } 
 

    try {
      const res = await axios.post(apiUrl, {
        identifier,
        password,
        recaptchaToken,
      });

      const token = res?.data?.token;
      if (!token) {
        setError("No token received from server.");
        setRecaptchaToken("");
        return;
      }

      localStorage.setItem(`${role}Token`, token);
      // Set ID based on role
      if (role === "admin") {
        localStorage.setItem("adminId", res.data?.admin?.id);
        navigate("/admin-dashboard");
      } 
    // else
    //      if (role === "centre") {
    //     localStorage.setItem("centreId", res.data?.centre?.id);
    //     navigate("/centre-dashboard");
    //   } 
    //   else if (role === "user") {
    //     localStorage.setItem("userId", res.data?.user?.id);
    //     localStorage.setItem("userDetails",JSON.stringify(res.data?.user));
    //     navigate("/user-dashboard");
    //   }
    } catch (err) {
      setError(err?.response?.data?.message || "Login failed.");
      setRecaptchaToken("");
    }
  };
  return (
    <>
      {/* ================================== Account Page Start =========================== */}
      <section className="account d-flex" style={{height:"100vh"}}>
        <div className="account__left d-md-flex d-none flx-align section-bg position-relative z-index-1 overflow-hidden">
          <div className="account-thumb">
            <img src="assets/images/services/Login.png" alt=""  loading="lazy"/>
            <div className="statistics animation bg-main text-center">
              {/* <h5 className="statistics__amount text-white">10k+</h5> */}
              <span className="statistics__text text-white font-14">
                Verified <br />
                Healthcare <br />
                Centre{" "}
              </span>
            </div>
          </div>
        </div>

        <div className="account__right padding-y-120 flx-align">
          <div className="account-content " style={{marginBottom:"5px"}}>
            <Link to="/" className="logo"> 
              <img
                src="assets/images/logo/BHARATLOGO-01.png"
                alt=""
                className="white-version"
              />

              <img
                src="assets/images/logo/BHARATLOGO-01.png"
                alt=""
                className="dark-version"
              />
            </Link>
{/* 
            <h4 className="account-content__title mb-40 text-capitalize">
              Welcome Back!
            </h4> */}
            {error && <div className="alert alert-danger">{error}</div>}
            <form onSubmit={handleLogin}>
              <div className="row gy-4">
                {/* <div className="col-12">
                  <label
                    htmlFor=""
                    className="form-label mb-2 font-18 font-heading fw-600"
                  >
                    Login As
                  </label>
                  <div className="position-relative">
                    <select
                      id="loginAs"
                      className="common-input common-input--bg w-100"
                      defaultValue=""
                      value={role}
                      onChange={(e) => setRole(e.target.value)}
                    >
                      <option value="" disabled>
                        Select Role
                      </option>
                      <option value="admin">Admin</option>
                      <option value="centre">Centre</option>
                      <option value="user">User</option>
                    </select>
                  </div>
                </div> */}
                <div className="col-12">
                  <label
                    htmlFor="email"
                    className="form-label mb-2 font-18 font-heading fw-600" style={{fontFamily:"inter"}}
                  >
                    Email or Phone
                  </label>

                  <div className="position-relative">
                    <input
                      type="text"
                      className="common-input common-input--bg common-input--withIcon"
                      id="email"
                      placeholder="Enter email or phone"
                      value={identifier}
                      onChange={(e) => setIdentifier(e.target.value)}
                      required
                    />

                    <span className="input-icon">
                      <img src="assets/images/icons/envelope-icon.svg" alt=""  loading="lazy" />
                    </span>
                  </div>
                </div>

                <div className="col-12">
                  <label
                    htmlFor="your-password"
                    className="form-label mb-2 font-18 font-heading fw-600" style={{fontFamily:"inter"}}
                  >
                    Password
                  </label>

                  <div className="position-relative">
                    <input
                      type="password"
                      className="common-input common-input--bg common-input--withIcon"
                      id="your-password"
                      placeholder="Enter Your Password"
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      required
                    />
                    <span
                      className="input-icon toggle-password cursor-pointer"
                      id="#your-password"
                    >
                      <img src="assets/images/icons/lock-icon.svg" alt=""  loading="lazy"/>
                    </span>
                  </div>
                </div>

                {/* <div className="col-12">
                  <div className="flx-between gap-1">
                    <Link
                      to="/forgot-password"
                      className="forgot-password text-decoration-underline text-main text-poppins font-14"
                    >
                      Forgot password?
                    </Link>
                  </div>
                </div> */}

                    <div className="col-12">
                  <div className="d-flex justify-content-center">
                    <ReCAPTCHA
                      sitekey={RECAPTCHA_SITE_KEY}
                      onChange={handleRecaptchaChange}
                      onExpired={() => setRecaptchaToken("")}
                      onErrored={() => setRecaptchaToken("")}
                    />
                  </div>
                </div>

                <div className="col-12">
                  <button
                    type="submit"
                    className="btn btn-main btn-lg w-100 pill"
                  >
                    {" "}
                    Sign In
                  </button>
                </div>

                {/* <div className="col-sm-12 mb-0">
                  <div className="have-account">
                    <p className="text font-14">
                     Login as a{" "}
                      <Link
                        className="link text-main text-decoration-underline fw-500"
                        to="/login"
                      >
                        User
                      </Link>
                    </p>
                  </div>
                </div> */}
              </div>
            </form>
          </div>
        </div>
      </section>
      {/* ================================== Account Page End =========================== */}
    </>
  );
};

export default LoginAdmin;

